@namespace Lumeo

@if (Role == AgentMessageRole.System)
{
    <div class="@SystemClass" style="@BubbleMaxWidthStyle" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
}
else if (Role == AgentMessageRole.Tool)
{
    <div class="@ToolWrapperClass" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
}
else if (Role == AgentMessageRole.User)
{
    <div class="@UserRowClass" @attributes="AdditionalAttributes">
        <div class="flex min-w-0 flex-col items-end gap-1">
            @if (!string.IsNullOrEmpty(Name) || Timestamp.HasValue)
            {
                <div class="flex items-center gap-2 text-xs text-muted-foreground">
                    @if (Timestamp.HasValue)
                    {
                        <time datetime="@IsoTimestamp(Timestamp.Value)">@FormatTimestamp(Timestamp.Value)</time>
                    }
                    @if (!string.IsNullOrEmpty(Name))
                    {
                        <span class="font-medium text-foreground">@Name</span>
                    }
                </div>
            }
            <div class="@UserBubbleClass" style="@BubbleMaxWidthStyle">
                @ChildContent
                @if (IsStreaming)
                {
                    <span class="ml-0.5 inline-block align-baseline bg-current animate-pulse" style="width: 2px; height: 1em;">&nbsp;</span>
                }
            </div>
        </div>
        @if (Avatar is not null)
        {
            <div class="shrink-0">@Avatar</div>
        }
    </div>
}
else
{
    <div class="@AssistantRowClass" @attributes="AdditionalAttributes">
        @if (Avatar is not null)
        {
            <div class="shrink-0 pt-0.5">@Avatar</div>
        }
        <div class="flex min-w-0 flex-1 flex-col gap-1">
            @if (!string.IsNullOrEmpty(Name) || Timestamp.HasValue)
            {
                <div class="flex items-center gap-2 text-xs text-muted-foreground">
                    @if (!string.IsNullOrEmpty(Name))
                    {
                        <span class="font-medium text-foreground">@Name</span>
                    }
                    @if (Timestamp.HasValue)
                    {
                        <time datetime="@IsoTimestamp(Timestamp.Value)">@FormatTimestamp(Timestamp.Value)</time>
                    }
                </div>
            }
            <div class="min-w-0 w-full text-sm leading-relaxed text-foreground">
                @ChildContent
                @if (IsStreaming)
                {
                    <span class="ml-0.5 inline-block align-baseline bg-current animate-pulse" style="width: 2px; height: 1em;">&nbsp;</span>
                }
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public AgentMessageRole Role { get; set; } = AgentMessageRole.Assistant;
    [Parameter] public RenderFragment? Avatar { get; set; }
    [Parameter] public string? Name { get; set; }
    [Parameter] public DateTimeOffset? Timestamp { get; set; }

    /// <summary>
    /// Time zone to render <see cref="Timestamp"/> in. When set, the timestamp
    /// is converted to this zone — pass the END USER'S zone here (in Blazor
    /// Server the component runs on the server, so the previous
    /// <c>ToLocalTime()</c> showed the SERVER'S zone, which is the bug #303
    /// fixed). When <c>null</c>, the timestamp is rendered in the offset it
    /// already carries (a <see cref="DateTimeOffset"/> knows its own offset), so
    /// it is deterministic and server-independent.
    /// </summary>
    [Parameter] public TimeZoneInfo? TimeZone { get; set; }

    /// <summary>Custom format string for the visible timestamp (default <c>"HH:mm"</c>).</summary>
    [Parameter] public string TimestampFormat { get; set; } = "HH:mm";

    /// <summary>Culture used to format the timestamp (defaults to <see cref="System.Globalization.CultureInfo.CurrentCulture"/>).</summary>
    [Parameter] public System.Globalization.CultureInfo? TimestampCulture { get; set; }

    [Parameter] public bool IsStreaming { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string UserRowClass => Cx.Merge("flex items-start justify-end gap-3", Class);
    private string UserBubbleClass => "rounded-2xl bg-primary px-4 py-3 text-sm leading-relaxed text-primary-foreground shadow-sm";
    // max-w-[80%] is an arbitrary Tailwind class not in the pre-compiled utility
    // bundle — use inline style so the bubble actually caps.
    private const string BubbleMaxWidthStyle = "max-width: 80%;";

    private string AssistantRowClass => Cx.Merge("flex items-start gap-3", Class);

    private string SystemClass =>
        Cx.Merge("mx-auto rounded-full bg-muted/60 px-3 py-1.5 text-center text-xs italic text-muted-foreground", Class);

    private string ToolWrapperClass => Cx.Merge("w-full", Class);

    // Render in the explicit TimeZone when supplied, otherwise in the offset the
    // DateTimeOffset already carries — never the server's local zone. Culture is
    // explicit so the displayed time doesn't drift with the server thread's
    // culture either.
    private string FormatTimestamp(DateTimeOffset ts)
    {
        var resolved = TimeZone is not null
            ? TimeZoneInfo.ConvertTime(ts, TimeZone)
            : ts;
        return resolved.ToString(TimestampFormat, TimestampCulture ?? System.Globalization.CultureInfo.CurrentCulture);
    }

    // Machine-readable, unambiguous source-of-truth for the <time> element:
    // always UTC ISO-8601 so assistive tech / client scripts can re-localize.
    private static string IsoTimestamp(DateTimeOffset ts) =>
        ts.UtcDateTime.ToString("yyyy-MM-ddTHH:mm:ssZ", System.Globalization.CultureInfo.InvariantCulture);

    public enum AgentMessageRole
    {
        User,
        Assistant,
        System,
        Tool
    }
}

@namespace Lumeo
@inject Services.IComponentInteropService Interop
@implements IAsyncDisposable

<div id="@_listId" class="@RootClass" role="log" aria-live="polite" aria-relevant="additions" @attributes="AdditionalAttributes">
    @if (Virtualize && Items is not null)
    {
        @* Virtualized path: <Virtualize> must sit directly inside the scroll
           container so its spacer elements measure correctly, so the flex-gap
           wrapper used by the default path is replaced with per-item bottom
           padding. Each item is a RenderFragment the consumer supplies. *@
        <Virtualize TItem="RenderFragment" Items="VirtualizedItems" ItemSize="ItemSize" OverscanCount="OverscanCount" Context="message">
            <div class="pb-4">
                @message
            </div>
        </Virtualize>
    }
    else
    {
        <div class="flex flex-col gap-4">
            @ChildContent
        </div>
    }
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool AutoScroll { get; set; } = true;

    /// <summary>
    /// Opt-in virtualization for long threads. When <c>true</c> AND
    /// <see cref="Items"/> is supplied, messages render through
    /// <see cref="Microsoft.AspNetCore.Components.Web.Virtualization.Virtualize{TItem}"/>
    /// so only the rows near the viewport are in the DOM. Leave <c>false</c> to
    /// use the simple <see cref="ChildContent"/> path (unchanged default).
    /// </summary>
    [Parameter] public bool Virtualize { get; set; }

    /// <summary>
    /// The per-message render fragments to virtualize. Each entry is rendered as
    /// one row (typically an <c>AgentMessage</c>). Only used when
    /// <see cref="Virtualize"/> is <c>true</c>; ignored otherwise.
    /// </summary>
    [Parameter] public IReadOnlyList<RenderFragment>? Items { get; set; }

    /// <summary>Estimated row height in pixels for the virtualizer (default 80).</summary>
    [Parameter] public float ItemSize { get; set; } = 80f;

    /// <summary>Extra rows to render above/below the viewport to smooth scrolling (default 4).</summary>
    [Parameter] public int OverscanCount { get; set; } = 4;

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _listId = LumeoIds.New("agent-message-list");
    private bool _observerRegistered;

    // Virtualize<TItem>.Items wants an ICollection<TItem>. Materialize it only
    // when the bound Items reference changes — recomputing (and copying, when
    // Items isn't already a collection) on every render would be O(n) per frame
    // during streaming and defeat virtualization.
    private IReadOnlyList<RenderFragment>? _itemsSnapshot;
    private ICollection<RenderFragment> _virtualizedItems = System.Array.Empty<RenderFragment>();
    private ICollection<RenderFragment> VirtualizedItems => _virtualizedItems;

    protected override void OnParametersSet()
    {
        if (!ReferenceEquals(_itemsSnapshot, Items))
        {
            _itemsSnapshot = Items;
            _virtualizedItems = Items as ICollection<RenderFragment>
                ?? Items?.ToList()
                ?? (ICollection<RenderFragment>)System.Array.Empty<RenderFragment>();
        }
    }

    private string RootClass =>
        Cx.Merge("flex w-full flex-col overflow-y-auto", Class);

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;
        if (!AutoScroll || _observerRegistered) return;
        try
        {
            _observerRegistered = true;
            await Interop.AiObserveAutoScroll(_listId);
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
    }

    public async ValueTask DisposeAsync()
    {
        if (_observerRegistered)
        {
            try
            {
                await Interop.AiDisposeAutoScroll(_listId);
            }
            catch (JSDisconnectedException) { /* ignore — circuit already gone */ }
        }
    }
}
